var express = require('express');
var cookieParser = require('cookie-parser');
var crypto = require('crypto');

var app = express();
app.use(cookieParser());

app.post('/login', function(req, res){
    var hashedPassword = crypto.createHash('sha256').update(req.body.password).digest('hex');

    if(req.body.rememberMe){
        res.cookie('username', req.body.username, { maxAge: 30 * 24 * 60 * 60 * 1000 });
        res.cookie('password', hashedPassword, { maxAge: 30 * 24 * 60 * 60 * 1000 });
    }

    // Login process continues
});

